package by.pavel.cache;

import java.util.Optional;

/**
 * ЗАДАЧА: LRU Cache с TTL
 * Время: 35-40 минут
 * Тема: Data Structures, Concurrency
 *
 * ТЗ:
 * Реализуй in-memory LRU Cache с поддержкой TTL (time-to-live).
 *
 * Требования:
 * - Кэш имеет фиксированную максимальную ёмкость (capacity)
 * - При достижении capacity — вытесняется наименее недавно использованный элемент (LRU)
 * - Каждый элемент имеет TTL (в секундах); по истечении — считается отсутствующим
 * - get() обновляет порядок использования (делает элемент "самым свежим")
 * - put() добавляет или обновляет элемент, сбрасывает TTL
 * - Реализация должна быть thread-safe
 *
 * Подсказка по структуре данных:
 * LinkedHashMap(capacity, 0.75f, true) с переопределённым removeEldestEntry()
 * даёт LRU-поведение "из коробки". Но подумай о потокобезопасности.
 *
 * Вопросы для обсуждения после реализации:
 * - Чем отличается LRU от LFU (Least Frequently Used)?
 * - Как реализовать O(1) get и put без LinkedHashMap (HashMap + DoubleLinkedList)?
 * - synchronized vs ReadWriteLock — когда что предпочтительнее?
 * - Как сделать lazy eviction vs background eviction (отдельный поток)?
 * - Как масштабировать: сегментированный кэш (как в ConcurrentHashMap)?
 */
public interface Cache<K, V> {

    /**
     * Возвращает значение по ключу.
     * Обновляет позицию элемента в LRU-порядке.
     * Возвращает empty если элемент отсутствует или TTL истёк.
     */
    Optional<V> get(K key);

    /**
     * Сохраняет значение. Если кэш заполнен — вытесняет LRU-элемент.
     * Перезаписывает существующий элемент и сбрасывает его TTL.
     */
    void put(K key, V value);

    /**
     * Удаляет элемент из кэша.
     * @return true если элемент существовал и был удалён
     */
    boolean remove(K key);

    /** Текущее количество живых (не просроченных) элементов в кэше. */
    int size();
}
